    def _make_bottom_nav_divider(self) -> QLabel:
        lbl = QLabel("|")
        try:
            lbl.setProperty("bottomNavDivider", True)
            lbl.setAlignment(
                Qt.AlignmentFlag.AlignHCenter | Qt.AlignmentFlag.AlignVCenter
            )
            lbl.setFixedWidth(12)
        except Exception:
            pass
        return lbl

    def _setup_bottom_nav_action_button_innards(
        self, btn: QPushButton, title: str, *, use_save_icon: bool
    ) -> None:
        """하단 우측 액션 버튼: 아이콘 + 한 줄 텍스트(clicked는 버튼에 유지)."""
        try:
            if btn.layout() is not None:
                return
        except Exception:
            return
        try:
            btn.setText("")
            btn.setProperty("bottomAction", False)
            btn.setProperty("bottomActionButton", True)
            btn.setLayoutDirection(Qt.LayoutDirection.LeftToRight)
        except Exception:
            pass
        try:
            h = QHBoxLayout(btn)
            h.setContentsMargins(8, 0, 10, 0)
            h.setSpacing(6)
            ic = QLabel(btn)
            ic.setFixedSize(18, 18)
            ic.setAlignment(
                Qt.AlignmentFlag.AlignHCenter | Qt.AlignmentFlag.AlignVCenter
            )
            ic.setProperty("bottomActionIcon", True)
            try:
                ic.setAttribute(
                    Qt.WidgetAttribute.WA_TransparentForMouseEvents, True
                )
            except Exception:
                pass
            _pix_ok = False
            try:
                st = self.style()
                if st is not None and use_save_icon:
                    pm = st.standardIcon(
                        QStyle.StandardPixmap.SP_DialogSaveButton
                    ).pixmap(QSize(18, 18))
                    if pm is not None and not pm.isNull():
                        ic.setPixmap(pm)
                        _pix_ok = True
            except Exception:
                pass
            if not _pix_ok:
                try:
                    ic.setText("□" if use_save_icon else "⇪")
                except Exception:
                    pass
            tx = QLabel(title, btn)
            tx.setProperty("bottomActionText", True)
            try:
                tx.setAttribute(
                    Qt.WidgetAttribute.WA_TransparentForMouseEvents, True
                )
            except Exception:
                pass
            h.addWidget(ic, 0)
            h.addWidget(tx, 0)
            h.addStretch(1)
        except Exception:
            pass

    def _on_bottom_nav_clicked(self, idx: int):
        try:
            if not hasattr(self, "tabs") or self.tabs is None:
                return
            if idx < 0 or idx >= int(self.tabs.count()):
                return
            self.tabs.setCurrentIndex(int(idx))
            self._set_bottom_nav_active(int(idx))
        except Exception:
            pass

    def _set_bottom_nav_active(self, idx: int):
        try:
            buttons = list(getattr(self, "_bottom_nav_buttons", None) or [])
            for i, b in enumerate(buttons):
                if b is None:
                    continue
                active = int(i) == int(idx)
                if hasattr(b, "set_tile_active"):
                    try:
                        b.set_tile_active(active)
                        try:
                            b.update()
                        except Exception:
                            pass
                    except Exception:
                        pass
                elif isinstance(b, QPushButton):
                    b.setStyleSheet(
                        (
                            "QPushButton {"
                            "background: #0b1224;"
                            "border: 2px solid #3b82f6;"
                            "color: #ffffff;"
                            "font-size: 14px;"
                            "font-weight: 900;"
                            "border-radius: 14px;"
                            "padding: 10px 18px;"
                            "}"
                            "QPushButton:hover {"
                            "background: #111b33;"
                            "border: 2px solid #60a5fa;"
                            "}"
                        )
                        if active
                        else (
                            "QPushButton {"
                            "background: transparent;"
                            "border: 1px solid transparent;"
                            "color: #e5e7eb;"
                            "font-size: 14px;"
                            "font-weight: 800;"
                            "border-radius: 14px;"
                            "padding: 10px 18px;"
                            "}"
                            "QPushButton:hover {"
                            "background: #111827;"
                            "border: 1px solid #334155;"
                            "}"
                        )
                    )
        except Exception:
            pass

    def _get_aits_runtime_state(self):
        try:
            orch = getattr(self, "orchestrator", None)
            if orch is not None and hasattr(orch, "get_runtime_state"):
                return orch.get_runtime_state()
            ctx = getattr(self, "app_context", None)
            if isinstance(ctx, dict):
                o = ctx.get("orchestrator")
                if o is not None and hasattr(o, "get_runtime_state"):
                    return o.get_runtime_state()
                rs = ctx.get("runtime_state")
                if rs is not None:
                    return rs
            rs = getattr(self, "runtime_state", None)
            if rs is not None:
                return rs
        except Exception:
            return None
        return None

    def _format_seconds_to_hhmmss(self, seconds: int) -> str:
        try:
            s = int(seconds)
        except (TypeError, ValueError):
            s = 0
        if s < 0:
            s = 0
        h = s // 3600
        m = (s % 3600) // 60
        sec = s % 60
        return f"{h:02d}:{m:02d}:{sec:02d}"

    def _get_aits_module_pack_runtime(self):
        try:
            orch = getattr(self, "orchestrator", None)
            if orch is not None and hasattr(orch, "get_last_module_pack_runtime"):
                return orch.get_last_module_pack_runtime()
            ctx = getattr(self, "app_context", None)
            if isinstance(ctx, dict):
                o = ctx.get("orchestrator")
                if o is not None and hasattr(o, "get_last_module_pack_runtime"):
                    return o.get_last_module_pack_runtime()
            return getattr(self, "last_module_pack_runtime", None)
        except Exception:
            return None
        return None

    def _set_aits_module_pack_labels(self) -> None:
        if not all(
            hasattr(self, n)
            for n in ("lbl_aits_pack_name", "lbl_aits_pack_timer", "lbl_aits_pack_summary")
        ):
            return
        try:
            pr = self._get_aits_module_pack_runtime()
            if pr is None:
                self.lbl_aits_pack_name.setText("AITS Module Pack: 연결 대기")
                self.lbl_aits_pack_timer.setText("AITS Pack Timer: 연결 대기")
                self.lbl_aits_pack_summary.setText(
                    "AITS Pack Summary: 모듈팩 상태를 불러오지 못했습니다."
                )
                return
            apid = getattr(pr, "active_pack_id", None)
            apid_str = "" if apid is None else str(apid).strip()
            pnk = (getattr(pr, "pack_name_ko", None) or "").strip()
            timer_en = bool(getattr(pr, "timer_enabled", False))
            try:
                rem = int(getattr(pr, "remaining_seconds", 0))
            except (TypeError, ValueError):
                rem = 0
            rsum = (getattr(pr, "runtime_summary_ko", None) or "").strip()

            if not apid_str:
                name = "AI 기본 모드"
                timer = "무기한"
                summ = rsum or "현재 모듈팩이 활성화되어 있지 않습니다."
            elif timer_en:
                name = pnk or apid_str
                timer = self._format_seconds_to_hhmmss(rem)
                summ = rsum or "—"
            else:
                name = pnk or apid_str
                timer = "무기한"
                summ = rsum or "—"

            self.lbl_aits_pack_name.setText(f"AITS Module Pack: {name}")
            self.lbl_aits_pack_timer.setText(f"AITS Pack Timer: {timer}")
            self.lbl_aits_pack_summary.setText(f"AITS Pack Summary: {summ}")
        except Exception:
            self.lbl_aits_pack_name.setText("AITS Module Pack: 연결 대기")
            self.lbl_aits_pack_timer.setText("AITS Pack Timer: 연결 대기")
            self.lbl_aits_pack_summary.setText(
                "AITS Pack Summary: 모듈팩 상태를 불러오지 못했습니다."
            )

    def _set_aits_override_labels(self) -> None:
        if not all(
            hasattr(self, n)
            for n in ("lbl_aits_override", "lbl_aits_override_summary")
        ):
            return
        try:
            rs = self._get_aits_runtime_state()
            if rs is None:
                self.lbl_aits_override.setText("AITS Override: 연결 대기")
                self.lbl_aits_override_summary.setText(
                    "AITS Override Summary: AITS 상태를 불러오는 중입니다."
                )
                return
            intel = getattr(rs, "intelligence", None)
            ai_dec = getattr(intel, "ai_decision", None) if intel else None
            if ai_dec is None:
                self.lbl_aits_override.setText("AITS Override: 확인 불가")
                self.lbl_aits_override_summary.setText(
                    "AITS Override Summary: 이번 사이클의 override 여부를 확인할 수 없습니다."
                )
                return
            raw_logic = getattr(ai_dec, "selected_strategy_logic", None)
            if raw_logic is None:
                logic_s = ""
            else:
                logic_s = raw_logic if isinstance(raw_logic, str) else str(raw_logic)
            logic_s = (logic_s or "").strip()
            if not logic_s:
                self.lbl_aits_override.setText("AITS Override: 확인 불가")
                self.lbl_aits_override_summary.setText(
                    "AITS Override Summary: 이번 사이클의 override 여부를 확인할 수 없습니다."
                )
                return
            raw_sum = getattr(ai_dec, "ai_summary_for_user", None)
            ai_summary = "" if raw_sum is None else str(raw_sum).strip()
            if "override_applied" in logic_s:
                summ = ai_summary or "현재 모듈팩의 영향으로 기본 판단이 한 단계 조정되었습니다."
                self.lbl_aits_override.setText("AITS Override: 적용됨")
                self.lbl_aits_override_summary.setText(f"AITS Override Summary: {summ}")
            else:
                self.lbl_aits_override.setText("AITS Override: 없음")
                self.lbl_aits_override_summary.setText(
                    "AITS Override Summary: 이번 사이클에서 모듈팩에 의한 판단 조정이 감지되지 않았습니다."
                )
        except Exception:
            try:
                self.lbl_aits_override.setText("AITS Override: 확인 불가")
                self.lbl_aits_override_summary.setText(
                    "AITS Override Summary: 이번 사이클의 override 여부를 확인할 수 없습니다."
                )
            except Exception:
                pass

    def _get_aits_effective_biases(self):
        """
        orchestrator -> last_module_pack_runtime -> bias 추출
        return dict or None
        """
        try:
            runtime = self._get_aits_module_pack_runtime()
            if runtime is None:
                return None
            return {
                "buy": getattr(runtime, "effective_buy_bias_delta", 0.0),
                "wait": getattr(runtime, "effective_wait_bias_delta", 0.0),
                "reduce": getattr(runtime, "effective_reduce_bias_delta", 0.0),
                "sell": getattr(runtime, "effective_sell_bias_delta", 0.0),
                "mode": getattr(runtime, "effective_risk_bias", None),
            }
        except Exception:
            return None

    def _format_bias_value(self, v):
        try:
            return f"{float(v):+.2f}"
        except Exception:
            return "+0.00"

    def _pick_aits_bias_color(self, buy: float, wait: float, reduce: float, sell: float) -> str:
        try:
            vals = [float(buy), float(wait), float(reduce), float(sell)]
            rep = max(vals, key=lambda x: abs(x))
            if abs(rep) < 0.05:
                return "#888888"
            if rep >= 0.15:
                return "#1f7a1f"
            if rep >= 0.05:
                return "#2e8b57"
            if rep <= -0.15:
                return "#b34747"
            if rep <= -0.05:
                return "#c07a2b"
            return "#888888"
        except Exception:
            return "#888888"

    def _pick_aits_bias_mode_color(self, mode: str) -> str:
        try:
            m = (mode or "").strip().lower()
            if m == "offensive":
                return "#1f7a1f"
            if m == "defensive":
                return "#b34747"
            return "#888888"
        except Exception:
            return "#888888"

    def _set_aits_bias_labels(self) -> None:
        if not all(
            hasattr(self, n)
            for n in ("lbl_aits_bias", "lbl_aits_bias_mode")
        ):
            return
        try:
            bias = self._get_aits_effective_biases()
            if bias is None:
                self.lbl_aits_bias.setText("AITS Bias: 연결 대기")
                self.lbl_aits_bias_mode.setText("AITS Bias Mode: 연결 대기")
                self.lbl_aits_bias.setStyleSheet("color: #888888;")
                self.lbl_aits_bias_mode.setStyleSheet("color: #888888;")
                return
            buy_v = float(bias.get("buy", 0.0))
            wait_v = float(bias.get("wait", 0.0))
            reduce_v = float(bias.get("reduce", 0.0))
            sell_v = float(bias.get("sell", 0.0))
            buy = self._format_bias_value(bias.get("buy", 0.0))
            wait = self._format_bias_value(bias.get("wait", 0.0))
            reduce = self._format_bias_value(bias.get("reduce", 0.0))
            sell = self._format_bias_value(bias.get("sell", 0.0))
            mode = str(bias.get("mode") or "neutral").strip() or "neutral"
            bias_color = self._pick_aits_bias_color(buy_v, wait_v, reduce_v, sell_v)
            mode_color = self._pick_aits_bias_mode_color(mode)
            self.lbl_aits_bias.setText(
                f"AITS Bias: buy={buy} | wait={wait} | reduce={reduce} | sell={sell}"
            )
            self.lbl_aits_bias_mode.setText(f"AITS Bias Mode: {mode}")
            self.lbl_aits_bias.setStyleSheet(f"color: {bias_color};")
            self.lbl_aits_bias_mode.setStyleSheet(f"color: {mode_color};")
        except Exception:
            self.lbl_aits_bias.setText("AITS Bias: 연결 대기")
            self.lbl_aits_bias_mode.setText("AITS Bias Mode: 연결 대기")
            self.lbl_aits_bias.setStyleSheet("color: #888888;")
            self.lbl_aits_bias_mode.setStyleSheet("color: #888888;")

    def _get_aits_order_adapter_result(self):
        try:
            orch = getattr(self, "orchestrator", None)
            if orch is not None and hasattr(orch, "get_last_order_adapter_result"):
                return orch.get_last_order_adapter_result()
            ctx = getattr(self, "app_context", None)
            if isinstance(ctx, dict):
                o = ctx.get("orchestrator")
                if o is not None and hasattr(o, "get_last_order_adapter_result"):
                    return o.get_last_order_adapter_result()
            return getattr(self, "last_order_adapter_result", None)
        except Exception:
            return None
        return None

    def _get_aits_execution_mode(self):
        try:
            orch = getattr(self, "orchestrator", None)
            if orch is not None and hasattr(orch, "get_execution_mode"):
                return orch.get_execution_mode()
            ctx = getattr(self, "app_context", None)
            if isinstance(ctx, dict):
                o = ctx.get("orchestrator")
                if o is not None and hasattr(o, "get_execution_mode"):
                    return o.get_execution_mode()
            return None
        except Exception:
            return None
        return None

    def _get_aits_orchestrator(self):
        try:
            orch = getattr(self, "orchestrator", None)
            if orch is not None:
                return orch
            ctx = getattr(self, "app_context", None)
            if isinstance(ctx, dict):
                o = ctx.get("orchestrator")
                if o is not None:
                    return o
        except Exception:
            return None
        return None

    def _sync_aits_exec_mode_combo(self) -> None:
        if not hasattr(self, "cmb_aits_exec_mode"):
            return
        try:
            mode = str(self._get_aits_execution_mode() or "disabled").strip()
            if mode not in ("disabled", "dry_run", "live"):
                mode = "disabled"
            self.cmb_aits_exec_mode.blockSignals(True)
            self.cmb_aits_exec_mode.setCurrentText(mode)
            self.cmb_aits_exec_mode.blockSignals(False)
            if hasattr(self, "lbl_aits_exec_mode_apply"):
                if self._get_aits_orchestrator() is None:
                    self.lbl_aits_exec_mode_apply.setText(
                        "AITS Execution Control: 오케스트레이터 연결 대기"
                    )
                else:
                    self.lbl_aits_exec_mode_apply.setText(
                        f"AITS Execution Control: 현재 모드 {mode}"
                    )
        except Exception:
            try:
                self.cmb_aits_exec_mode.blockSignals(True)
                self.cmb_aits_exec_mode.setCurrentText("disabled")
                self.cmb_aits_exec_mode.blockSignals(False)
            except Exception:
                pass
            if hasattr(self, "lbl_aits_exec_mode_apply"):
                self.lbl_aits_exec_mode_apply.setText("AITS Execution Control: 연결 대기")

    def _on_aits_exec_mode_changed(self, value: str) -> None:
        try:
            orch = self._get_aits_orchestrator()
            if orch is None or not hasattr(orch, "set_execution_mode"):
                self.lbl_aits_exec_mode_apply.setText(
                    "AITS Execution Control: 오케스트레이터 연결 대기"
                )
                return
            selected = str(value or "").strip() or "disabled"
            orch.set_execution_mode(selected)
            applied = "disabled"
            if hasattr(orch, "get_execution_mode"):
                applied = str(orch.get_execution_mode() or "disabled").strip() or "disabled"
            if applied not in ("disabled", "dry_run", "live"):
                applied = "disabled"
            self.lbl_aits_exec_mode_apply.setText(f"AITS Execution Control: 적용됨 ({applied})")
            self._sync_aits_exec_mode_combo()
        except Exception:
            try:
                self.lbl_aits_exec_mode_apply.setText("AITS Execution Control: 적용 실패")
            except Exception:
                pass
        try:
            self._update_aits_overview_latest()
        except Exception:
            pass

    def _set_aits_order_adapter_labels(self) -> None:
        if not all(
            hasattr(self, n)
            for n in ("lbl_aits_exec_mode", "lbl_aits_orders", "lbl_aits_orders_summary")
        ):
            return
        try:
            mode = self._get_aits_execution_mode()
            ar = self._get_aits_order_adapter_result()
            if ar is None:
                if mode:
                    exec_text = str(mode)
                    orders_text = "결과 대기"
                    summary_text = "이번 사이클의 주문 실행 결과를 기다리는 중입니다."
                else:
                    exec_text = "연결 대기"
                    orders_text = "연결 대기"
                    summary_text = "주문 실행 결과를 불러오지 못했습니다."
            else:
                exec_text = getattr(ar, "execution_mode", None) or (mode or "확인 불가")
                submitted = int(getattr(ar, "submitted_count", 0) or 0)
                blocked = int(getattr(ar, "blocked_count", 0) or 0)
                failed = int(getattr(ar, "failed_count", 0) or 0)
                skipped = int(getattr(ar, "skipped_count", 0) or 0)
                summary_text = getattr(ar, "summary_ko", "") or "주문 실행 결과 요약이 없습니다."
                orders_text = (
                    f"submitted={submitted} | blocked={blocked} | failed={failed} | skipped={skipped}"
                )
            self.lbl_aits_exec_mode.setText(f"AITS Execution Mode: {exec_text}")
            self.lbl_aits_orders.setText(f"AITS Orders: {orders_text}")
            self.lbl_aits_orders_summary.setText(f"AITS Orders Summary: {summary_text}")
        except Exception:
            self.lbl_aits_exec_mode.setText("AITS Execution Mode: 연결 대기")
            self.lbl_aits_orders.setText("AITS Orders: 연결 대기")
            self.lbl_aits_orders_summary.setText(
                "AITS Orders Summary: 주문 실행 결과를 불러오지 못했습니다."
            )

    def _toggle_aits_overview(self) -> None:
        try:
            expanded = not bool(getattr(self, "_aits_overview_expanded", False))
            self._aits_overview_expanded = expanded

            try:
                host = getattr(self, "_aits_overview_scroll_host", None)
                if host is not None:
                    host.setVisible(expanded)
                    host.setMaximumHeight(96 if expanded else 0)
                    host.setMinimumHeight(0)
            except Exception:
                pass

            try:
                if hasattr(self, "_aits_overview_scroll"):
                    self._aits_overview_scroll.setVisible(expanded)
                    self._aits_overview_scroll.setMaximumHeight(96 if expanded else 0)
            except Exception:
                pass

            try:
                grp = getattr(self, "_aits_status_group", None)
                if grp is not None:
                    grp.setVisible(expanded)
                    grp.setMaximumHeight(102 if expanded else 0)
                    grp.setMinimumHeight(0)
            except Exception:
                pass

            try:
                if hasattr(self, "lbl_aits_overview_latest"):
                    self.lbl_aits_overview_latest.setVisible(expanded)
            except Exception:
                pass

            try:
                if hasattr(self, "btn_aits_overview_toggle"):
                    self.btn_aits_overview_toggle.setText("접기 ▲" if expanded else "펼치기 ▼")
            except Exception:
                pass

            try:
                self._apply_settings_patch(
                    {"ui_state": {"aits_overview_expanded": expanded}},
                    reason="aits_overview_toggle",
                )
            except Exception:
                pass
        except Exception:
            pass

    def _update_aits_overview_latest(self) -> None:
        try:
            if not hasattr(self, "lbl_aits_overview_latest"):
                return
            _names = (
                "lbl_aits_regime",
                "lbl_aits_action",
                "lbl_aits_summary",
                "lbl_aits_market",
                "lbl_aits_oversight",
                "lbl_aits_pack_name",
                "lbl_aits_pack_timer",
                "lbl_aits_pack_summary",
                "lbl_aits_override",
                "lbl_aits_override_summary",
                "lbl_aits_bias",
                "lbl_aits_bias_mode",
                "lbl_aits_exec_mode",
                "lbl_aits_orders",
                "lbl_aits_orders_summary",
                "lbl_aits_exec_mode_apply",
            )
            line = ""
            for _name in reversed(_names):
                w = getattr(self, _name, None)
                if w is None:
                    continue
                try:
                    t = (w.text() or "").strip()
                except Exception:
                    continue
                if t:
                    line = t
                    break
            if not line:
                line = "연결 대기"
            if line.startswith("최신:"):
                out = line
            else:
                out = f"최신: {line}"
            self.lbl_aits_overview_latest.setText(out)
        except Exception:
            pass

    def _refresh_aits_status_view(self):
        if not all(
            hasattr(self, n)
            for n in (
                "lbl_aits_regime",
                "lbl_aits_action",
                "lbl_aits_summary",
                "lbl_aits_market",
                "lbl_aits_oversight",
                "lbl_aits_pack_name",
                "lbl_aits_pack_timer",
                "lbl_aits_pack_summary",
                "lbl_aits_override",
                "lbl_aits_override_summary",
                "lbl_aits_bias",
                "lbl_aits_bias_mode",
                "lbl_aits_exec_mode",
                "lbl_aits_orders",
                "lbl_aits_orders_summary",
                "cmb_aits_exec_mode",
                "lbl_aits_exec_mode_apply",
            )
        ):
            return
        try:
            rs = self._get_aits_runtime_state()
            if rs is None:
                self.lbl_aits_regime.setText("AITS Regime: 연결 대기")
                self.lbl_aits_action.setText("AITS Action: 연결 대기")
                self.lbl_aits_summary.setText("AITS Summary: AITS 상태 없음")
                self.lbl_aits_market.setText("AITS Market: AITS 상태 없음")
                self.lbl_aits_oversight.setText("AITS Oversight: AITS 상태 없음")
                self._set_aits_module_pack_labels()
                self._set_aits_override_labels()
                self._set_aits_bias_labels()
                self._set_aits_order_adapter_labels()
                self._sync_aits_exec_mode_combo()
                return
            market = getattr(rs, "market", None)
            regime = getattr(market, "regime", None) if market else None
            regime_lbl = getattr(regime, "label", "") if regime else ""
            intel = getattr(rs, "intelligence", None)
            ai_dec = getattr(intel, "ai_decision", None) if intel else None
            action = getattr(ai_dec, "action", "") if ai_dec else ""
            summary = getattr(ai_dec, "ai_summary_for_user", "") if ai_dec else ""
            expl = getattr(rs, "explainability", None)
            mstory = getattr(expl, "current_market_story", "") if expl else ""
            over = getattr(rs, "oversight", None)
            ovsum = getattr(over, "oversight_summary", "") if over else ""
            self.lbl_aits_regime.setText(f"AITS Regime: {regime_lbl or '—'}")
            self.lbl_aits_action.setText(f"AITS Action: {action or '—'}")
            self.lbl_aits_summary.setText(f"AITS Summary: {summary or '—'}")
            self.lbl_aits_market.setText(f"AITS Market: {mstory or '—'}")
            self.lbl_aits_oversight.setText(f"AITS Oversight: {ovsum or '—'}")
            self._set_aits_module_pack_labels()
            self._set_aits_override_labels()
            self._set_aits_bias_labels()
            self._set_aits_order_adapter_labels()
            self._sync_aits_exec_mode_combo()
        except Exception:
            self.lbl_aits_regime.setText("AITS Regime: 연결 대기")
            self.lbl_aits_action.setText("AITS Action: 연결 대기")
            self.lbl_aits_summary.setText("AITS Summary: AITS 상태 없음")
            self.lbl_aits_market.setText("AITS Market: AITS 상태 없음")
            self.lbl_aits_oversight.setText("AITS Oversight: AITS 상태 없음")
            try:
                self._set_aits_module_pack_labels()
            except Exception:
                pass
            try:
                self._set_aits_override_labels()
            except Exception:
                pass
            try:
                self._set_aits_bias_labels()
            except Exception:
                pass
            try:
                self._set_aits_order_adapter_labels()
            except Exception:
                pass
            try:
                self._sync_aits_exec_mode_combo()
            except Exception:
                pass
        finally:
            try:
                self._update_aits_overview_latest()
            except Exception:
                pass

    def _get_aits_engine_box_style(self, provider: str) -> str:
        provider = str(provider or "").strip().lower()

        if provider == "gpt":
            bg = "#dff7f5"
            bd = "#4db6ac"
            fg = "#0f4f4b"
        elif provider == "gemini":
            bg = "#efe7ff"
            bd = "#8b6fd6"
            fg = "#4b3a7a"
        else:
            bg = "#eef5e6"
            bd = "#7ea05a"
            fg = "#3d5b2a"

        return (
            "QLabel {"
            f"background: {bg};"
            f"border: 1px solid {bd};"
            "border-radius: 8px;"
            f"color: {fg};"
            "font-weight: 700;"
            "padding: 6px 12px;"
            "}"
        )

    def _get_aits_badge_style(self, badge_state: str) -> str:
        s = str(badge_state or "").strip().lower()

        if s == "ready":
            bg = "#f0fdf4"
            bd = "#86efac"
            fg = "#15803d"
        elif s == "warn":
            bg = "#fffbeb"
            bd = "#fdba74"
            fg = "#92400e"
        elif s == "error":
            bg = "#fef2f2"
            bd = "#fca5a5"
            fg = "#991b1b"
        else:
            bg = "#f1f5f9"
            bd = "#cbd5e1"
            fg = "#334155"

        return (
            "QLabel {"
            "font-family: 'Noto Sans KR', 'Malgun Gothic', sans-serif;"
            f"background: {bg};"
            f"border: 1px solid {bd};"
            "border-radius: 15px;"
            f"color: {fg};"
            "font-weight: 800;"
            "font-size: 12px;"
            "padding: 5px 14px;"
            "}"
        )

    def _apply_aits_ai_engine_status_line_style(self, text: str | None = None) -> None:
        try:
            lb = getattr(self, "lbl_aits_ai_engine_status", None)
            if lb is None:
                return
            t = str(text if text is not None else lb.text() or "")
            _warn_keys = ("불일치", "대기", "주의", "연결 확인 필요")
            _is_warn = any(k in t for k in _warn_keys)
            if _is_warn:
                lb.setStyleSheet(
                    "QLabel {"
                    "background: #f7f9fb;"
                    "border: 1px solid #e0b35b;"
                    "border-radius: 6px;"
                    "color: #7a5612;"
                    "padding: 4px 8px;"
                    "font-weight: 600;"
                    "font-size: 11px;"
                    "}"
                )
            else:
                lb.setStyleSheet(
                    "QLabel {"
                    "background: #f7f9fb;"
                    "border: 1px solid #d8dee6;"
                    "border-radius: 6px;"
                    "color: #425466;"
                    "padding: 4px 8px;"
                    "font-weight: 600;"
                    "font-size: 11px;"
                    "}"
                )
        except Exception:
            pass

    # [UI MASTER PLAN Phase 1 / PATCH 1-3]
    # 엔진 선택과 상태를 텍스트보다 색상으로 먼저 인지하게 만든다.
    # - 큰 박스 = 엔진 종류 색상
    # - 배지 = 상태 색상
    # - 상태 줄 = 중립 정보 카드 + 경고만 약한 강조
    # 로직은 변경하지 않고 시각 인지성만 강화한다.

    def _update_top_badge(self):
        """상단 배지: 엔진명 미노출, AI 상태 요약만."""
        try:
            selected_provider = self._get_aits_engine_ssot()
            actual_provider = self._get_aits_last_response_provider()
            actual_engine_raw = ""
            try:
                from app.services import ai_reco
                last_dec = ai_reco.get_last_decision() or {}
                actual_engine_raw = (last_dec.get("actual_engine") or "").strip()
            except Exception:
                pass
            stage = (getattr(self, "_gpt_status_stage", "") or "").strip().lower()
            _hid_st = ""
            try:
                _hid_st = self.lbl_aits_ai_engine_status.text().strip()
            except Exception:
                pass
            _hid_l = _hid_st.lower()
            _hid_err = ("오류" in _hid_st) or ("fail" in _hid_l) or ("실패" in _hid_st)

            badge_state = "idle"
            if _hid_err or stage in ("error", "failed", "fail"):
                badge_txt = "AI 상태 | 오류"
                badge_state = "error"
            elif actual_engine_raw == "simple_momo" or stage == "degraded":
                badge_txt = "AI 상태 | 주의"
                badge_state = "warn"
            elif selected_provider == "basic":
                if actual_provider in ("gpt", "gemini"):
                    badge_txt = "AI 상태 | 주의"
                    badge_state = "warn"
                elif actual_provider == "basic":
                    badge_txt = "AI 상태 | 준비됨"
                    badge_state = "ready"
                else:
                    badge_txt = "AI 상태 | 대기"
                    badge_state = "idle"
            elif selected_provider in ("gpt", "gemini"):
                if actual_provider == selected_provider:
                    badge_txt = "AI 상태 | 준비됨"
                    badge_state = "ready"
                elif actual_provider:
                    badge_txt = "AI 상태 | 주의"
                    badge_state = "warn"
                else:
                    badge_txt = "AI 상태 | 대기"
                    badge_state = "idle"
            else:
                badge_txt = "AI 상태 | 대기"
                badge_state = "idle"
            if hasattr(self, "ai_status_text") and self.ai_status_text is not None:
                self.ai_status_text.setVisible(True)
                self.ai_status_text.setText(badge_txt)
                try:
                    self.ai_status_text.setStyleSheet(
                        self._get_aits_badge_style(badge_state)
                    )
                except Exception:
                    pass
            try:
                self._update_aits_ops_summary()
                self._update_aits_briefing()
            except Exception:
                pass
        except Exception:
            pass

    # [PATCH 5-1]
    # 엔진 표시 기준은 _get_aits_engine_ssot() 단일값을 사용한다.
    # 실제 연결 성공 여부 / 모델명 / API 응답 모델명은
    # 이후 5-2 단계에서 별도 처리한다.
    # 현재 단계는 "무슨 엔진을 선택했는지" 정확히 보여주는 것이 목적이다.

    def _update_engine_status_box(self):
        """새로고침 오른쪽 큰 박스: 선택 엔진 종류(SSOT)만 표시. 모델명은 표기하지 않음."""
        try:
            if not getattr(self, "_engine_ui_unified_done", False):
                for name in ("gpt_test_header_status", "gpt_decision_summary"):
                    w = getattr(self, name, None)
                    if w is not None:
                        try:
                            w.setVisible(False)
                        except Exception:
                            pass
                self._engine_ui_unified_done = True
            provider = self._get_aits_engine_ssot()
            try:
                if hasattr(self, "lbl_engine_status") and self.lbl_engine_status is not None:
                    self.lbl_engine_status.setStyleSheet(
                        self._get_aits_engine_box_style(provider)
                    )
            except Exception:
                pass
            if provider == "gpt":
                provider_label = "OpenAI"
            elif provider == "gemini":
                provider_label = "Gemini"
            else:
                provider_label = "Basic AI"

            stage = (getattr(self, "_gpt_status_stage", "") or "").strip().lower()
            box_txt = "AI Engine | %s" % provider_label

            if hasattr(self, "lbl_engine_status") and self.lbl_engine_status is not None:
                self.lbl_engine_status.setText(box_txt)
                try:
                    self.lbl_engine_status.setFixedHeight(36)
                except Exception:
                    pass
            self._log.info("[ENGINE-UI] provider=%s stage=%s", provider, stage or "—")
            try:
                self._update_aits_ops_summary()
                self._update_aits_briefing()
            except Exception:
                pass
        except Exception as e:
            self._log.debug("[ENGINE-UI] box err=%s", str(e)[:80])

    def _update_aits_ops_summary(self):
        """E-1: 선택/실제/연결/모드 한 줄 운영 신뢰 바 + 우측 엔진 카드 동기화."""
        try:
            w = getattr(self, "lbl_aits_ops_summary", None)
            if w is None:
                return

            def _ko_engine(code: str) -> str:
                c = str(code or "").strip().lower()
                if c == "gpt":
                    return "GPT"
                if c == "gemini":
                    return "Gemini"
                if c in ("basic", "local", ""):
                    return "Basic"
                return str(code or "—").strip() or "—"

            def _norm_eng(c: str) -> str:
                x = str(c or "").strip().lower()
                if x in ("", "local"):
                    return "basic"
                return x

            sel_code = "basic"
            try:
                sel_code = str(self._get_aits_engine_ssot()).lower()
            except Exception:
                pass
            sel_txt = _ko_engine(sel_code)
            s_norm = _norm_eng(sel_code)

            act_raw = ""
            try:
                act_raw = str(self._get_aits_last_response_provider() or "").strip().lower()
            except Exception:
                act_raw = ""
            if not act_raw:
                act_txt = "Basic" if s_norm == "basic" else "확인중"
                a_norm = "basic" if s_norm == "basic" else ""
            else:
                act_txt = _ko_engine(act_raw)
                a_norm = _norm_eng(act_raw)

            status_source = ""
            try:
                status_source = self.lbl_aits_ai_engine_status.text().strip()
            except Exception:
                pass
            low = status_source.lower()
            err = (
                ("오류" in status_source)
                or ("fail" in low)
                or ("실패" in status_source)
                or ("mismatch" in low)
            )
            wait = (
                ("대기" in status_source)
                or ("connecting" in low)
                or ("연결중" in status_source)
            )
            ready = ("준비" in status_source) or ("정상" in status_source) or ("ready" in low)

            stage = (getattr(self, "_gpt_status_stage", "") or "").strip().lower()
            if s_norm == "gpt" and ("error" in stage or "fail" in stage):
                err = True

            conn = "확인중"
            if s_norm == "basic":
                conn = "준비완료"
            elif s_norm == a_norm and a_norm and ready and not err:
                conn = "준비완료"
            elif s_norm in ("gemini", "gpt") and a_norm == "basic":
                lab = "Gemini" if s_norm == "gemini" else "GPT"
                if err:
                    conn = f"{lab} 연결오류 (Basic 대기)"
                elif wait or not ready:
                    conn = f"{lab} 연결중"
                else:
                    conn = f"{lab} 연결중"
            elif s_norm in ("gemini", "gpt") and a_norm == s_norm:
                if err:
                    conn = f"{sel_txt} 연결오류 (Basic 대기)"
                elif wait and not ready:
                    conn = f"{sel_txt} 연결중"
                elif ready:
                    conn = "준비완료"
                else:
                    conn = "확인중"
            else:
                if err:
                    conn = "오류"
                elif wait:
                    conn = "연결중"
                elif ready:
                    conn = "준비완료"
                else:
                    conn = "확인중"

            mode_raw = "disabled"
            try:
                mode_raw = str(self._get_aits_execution_mode() or "disabled").strip()
            except Exception:
                pass
            if mode_raw not in ("disabled", "dry_run", "live"):
                mode_raw = "disabled"
            mode_kr = {"disabled": "비활성", "dry_run": "모의", "live": "실거래"}.get(
                mode_raw, mode_raw
            )

            out = (
                f"선택엔진: {sel_txt} | 실제엔진: {act_txt} | 연결상태: {conn} | 모드: {mode_kr}"
            )
            w.setText(out)

            tier = "ok"
            if err or ("연결오류" in conn) or (conn == "오류"):
                tier = "err"
            elif ("연결중" in conn) or (conn == "확인중") or (sel_txt != act_txt):
                tier = "warn"
            elif conn == "준비완료" and s_norm == "basic":
                tier = "basic_ok"

            if tier == "err":
                bg, bd, fg = "#fef2f2", "#ef4444", "#991b1b"
            elif tier == "warn":
                bg, bd, fg = "#fffbeb", "#f97316", "#92400e"
            elif tier == "basic_ok":
                bg, bd, fg = "#f0fdf4", "#86efac", "#14532d"
            else:
                bg, bd, fg = "#f0fdf4", "#22c55e", "#14532d"

            w.setStyleSheet(
                "#aitsOpsSummary{"
                "font-family:'Noto Sans KR','Malgun Gothic',sans-serif;"
                "background:#ffffff;"
                "border:1px solid #e5e7eb;"
                "border-radius:14px;"
                "padding:6px 12px;"
                "font-size:12px;"
                "font-weight:700;"
                "color:#334155;"
                "}"
            )

            _sel_lb = getattr(self, "_lbl_engine_card_selected", None)
            _mod_lb = getattr(self, "_lbl_engine_card_model", None)
            _st_lb = getattr(self, "_lbl_engine_card_status", None)
            _dot_lb = getattr(self, "_lbl_engine_card_status_dot", None)
            if _sel_lb is not None:
                try:
                    _sel_lb.setText(f"선택: {sel_txt}")
                except Exception:
                    pass
            _model_nm = "qwen2.5"
            try:
                if hasattr(self, "cmb_local_model") and self.cmb_local_model is not None:
                    _model_nm = (
                        (self.cmb_local_model.currentText() or "").strip() or _model_nm
                    )
            except Exception:
                pass
            if _mod_lb is not None:
                try:
                    _mod_lb.setText(f"모델: {_model_nm}")
                except Exception:
                    pass
            _eng_stat = (conn or "").strip() or "확인중"
            if _st_lb is not None:
                try:
                    _st_lb.setText(f"상태: {_eng_stat}")
                except Exception:
                    pass
            if _dot_lb is not None:
                try:
                    _dot_lb.setText("●")
                except Exception:
                    pass
                if tier == "err":
                    dot_color = "#ef4444"
                elif tier == "warn":
                    dot_color = "#f97316"
                else:
                    dot_color = "#22c55e"
                try:
                    _dot_lb.setStyleSheet(
                        f"color:{dot_color}; font-size:11px; font-weight:800; "
                        "background:transparent; border:none;"
                    )
                except Exception:
                    pass

            frame = getattr(self, "_frame_aits_engine_card", None)
            if frame is not None:
                frame.setStyleSheet(
                    "QFrame#aitsEngineSummaryCard {"
                    "background:#ffffff;"
                    "border:1px solid #e5e7eb;"
                    "border-radius:16px;"
                    "font-family:'Noto Sans KR','Malgun Gothic',sans-serif;"
                    "}"
                )
        except Exception:
            pass

    def _log_aits_validation_summary(self, tag: str = ""):
        try:
            selected_engine = ""
            actual_engine = ""

            try:
                selected_engine = str(self._get_aits_engine_ssot() or "")
            except Exception:
                pass

            try:
                actual_engine = str(self._get_aits_last_response_provider() or "")
            except Exception:
                pass

            managed = getattr(self, "ai_managed_rows", None) or []
            managed_syms = []
            for row in managed:
                if isinstance(row, dict):
                    sym = str(row.get("symbol", "") or row.get("market", "") or "").strip()
                    if sym:
                        managed_syms.append(sym)

            self._safe_log_info(
                f"[AITS][Validation] summary{('|' + tag) if tag else ''} | "
                f"selected_engine={selected_engine} | actual_engine={actual_engine} | "
                f"managed_count={len(managed_syms)} | managed_symbols={','.join(managed_syms[:20])}"
            )
        except Exception:
            pass

    def _update_aits_briefing(self):
        try:
            lb = getattr(self, "lbl_aits_briefing", None)
            if lb is None:
                return

            msg = "AI 브리핑: 시장 데이터 수집 중"

            txt = ""
            try:
                txt = self.lbl_ai_status.text().strip()
            except Exception:
                txt = ""

            if txt:
                msg = "AI 브리핑: " + txt.replace("\n", " / ")

            try:
                from PySide6.QtGui import QFontMetrics

                cw = int(lb.width() or 0)
                if cw > 80:
                    fm = QFontMetrics(lb.font())
                    msg = fm.elidedText(msg, Qt.TextElideMode.ElideRight, cw - 8)
            except Exception:
                pass

            lb.setText(msg)
        except Exception:
            pass

    def _update_engine_ui_ssot(self):
        """두 계층 분리: 상단 배지(actual만) + 하단 박스(실시간 상태)."""
        try:
            self._update_top_badge()
            self._update_engine_status_box()
            actual = ""
            try:
                from app.services import ai_reco
                last_dec = ai_reco.get_last_decision() or {}
                actual = (last_dec.get("actual_engine") or "").strip()
            except Exception:
                pass
            if actual.startswith("gpt-"):
                prev = getattr(self, "_last_actual_engine", "")
                if prev != actual:
                    self._last_actual_engine = actual
                    self._log.info("[ENGINE-SWITCH] actual_engine=%s", actual)
            else:
                self._last_actual_engine = actual or ""
            try:
                self._update_aits_ops_summary()
                self._update_aits_briefing()
            except Exception:
                pass
            try:
                self._log_aits_validation_summary("engine_ui")
            except Exception:
                pass
        except Exception as e:
            self._log.debug("[ENGINE-UI] update err=%s", str(e)[:80])

    def _update_active_engine_label(self):
        """
        엔진 중복 표기를 줄이기 위해 Active 라벨은 기본적으로 숨긴다.
        메인 엔진 표시는 lbl_engine_status(큰 박스) 1곳만 사용한다.
        """
        try:
            self._get_aits_engine_ssot()  # 향후 라벨 재노출 시에도 동일 SSOT 기준
            obj = getattr(self, "lbl_active_engine", None)
            if obj is not None:
                if hasattr(obj, "setText"):
                    obj.setText("")
                if hasattr(obj, "setVisible"):
                    obj.setVisible(False)
        except Exception:
            pass

    def _update_ai_status(self):
        """우측상단 표시: 엔진 종류는 _get_aits_engine_ssot() 기준으로 lbl_engine_status에 반영."""
        try:
            self._update_engine_ui_ssot()
        except Exception:
            pass
        try:
            self._refresh_aits_status_view()
        except Exception:
            pass
        try:
            self._update_aits_ops_summary()
            self._update_aits_briefing()
        except Exception:
            pass

    def _set_ai_provider_ui_active(self, provider: str):
        """공통설정: 선택한 박스만 활성화·스타일 적용·우측상단 배지 색상 동기화."""
        provider = (provider or "local").strip().lower()
        if provider not in ("gpt", "gemini", "local"):
            provider = "local"
        self._ai_provider_box_active = provider
        if hasattr(self, "cb_ai_provider"):
            self.cb_ai_provider.setCurrentText(provider)
        self._log.info("[AI-BOX] selected=%s", provider)

        # 박스별 enable/disable
        gpt_only = provider == "gpt"
        gemini_only = provider == "gemini"
        if hasattr(self, "ed_openai_key"):
            self.ed_openai_key.setEnabled(gpt_only)
        if hasattr(self, "ed_openai_model"):
            self.ed_openai_model.setEnabled(gpt_only)
        if hasattr(self, "ed_gemini_key"):
            self.ed_gemini_key.setEnabled(gemini_only)
        if hasattr(self, "cmb_gemini_model"):
            self.cmb_gemini_model.setEnabled(gemini_only)
        if hasattr(self, "btn_test_gpt"):
            self.btn_test_gpt.setEnabled(gpt_only)
        if hasattr(self, "btn_test_gemini"):
            self.btn_test_gemini.setEnabled(gemini_only)
        if hasattr(self, "btn_openai_usage"):
            self.btn_openai_usage.setEnabled(gpt_only)
        local_en = provider == "local"
        if hasattr(self, "inp_local_url"):
            self.inp_local_url.setEnabled(local_en)
        if hasattr(self, "cmb_local_model"):
            self.cmb_local_model.setEnabled(local_en)
        if hasattr(self, "btn_test_local_ai"):
            self.btn_test_local_ai.setEnabled(local_en)
        if hasattr(self, "btn_ollama_install_guide"):
            self.btn_ollama_install_guide.setEnabled(local_en)
        # 모델 설치 버튼은 _update_model_buttons_status에서 설치 상태에 따라 활성화/비활성화
        # LOCAL 박스 활성화 시 모델 버튼 상태 확인 (설치 여부에 따라 활성화/비활성화)
        if local_en and hasattr(self, "_check_and_update_model_buttons"):
            QTimer.singleShot(300, self._check_and_update_model_buttons)
        elif not local_en:
            # LOCAL 박스 비활성화 시 모든 모델 버튼 비활성화
            for btn_name in ["btn_install_qwen", "btn_install_llama", "btn_install_mistral"]:
                if hasattr(self, btn_name):
                    getattr(self, btn_name).setEnabled(False)

        # 박스 배경색: 비활성=흰색, 활성=강조색
        gpt_bg = "#D9F1FF" if gpt_only else "#ffffff"
        gemini_bg = "#E3F2FD" if gemini_only else "#ffffff"
        local_bg = "#DFF5E1" if local_en else "#ffffff"
        gpt_border = "#90CAF9" if gpt_only else "#d0d7de"
        gemini_border = "#64B5F6" if gemini_only else "#d0d7de"
        local_border = "#81C784" if local_en else "#d0d7de"
        if hasattr(self, "gpt_box"):
            self.gpt_box.setStyleSheet(
                f"QGroupBox {{ background-color: {gpt_bg}; border: 1px solid {gpt_border}; border-radius: 8px; padding: 8px; }}"
            )
        if hasattr(self, "gemini_box"):
            self.gemini_box.setStyleSheet(
                f"QGroupBox {{ background-color: {gemini_bg}; border: 1px solid {gemini_border}; border-radius: 8px; padding: 8px; }}"
            )
        if hasattr(self, "local_box"):
            self.local_box.setStyleSheet(
                f"#aits_local_basic_engine_box {{ background-color: {local_bg}; border: 1px solid {local_border}; border-radius: 8px; padding: 8px; margin-top: 18px; padding-top: 6px; border-top: 1px solid #e2e8f0; }}"
            )

        # 우측상단 배지 + 큰 박스: 선택 엔진 SSOT 기준으로 갱신
        try:
            self._update_engine_ui_ssot()
        except Exception as e:
            self._log.warning("[UI-AI-STATUS] ERROR: %s", str(e)[:80])

    def _on_ai_engine_changed(self, engine_text: str):
        eng = str(engine_text or "").strip()
        if not hasattr(self, "cmb_ai_model") or self.cmb_ai_model is None:
            return
        self.cmb_ai_model.clear()
        if eng == "OpenAI":
            self.cmb_ai_model.addItems(["gpt-4o-mini", "gpt-4o"])
            if hasattr(self, "ed_ai_api_key"):
                self.ed_ai_api_key.setEnabled(True)
                self.ed_ai_api_key.setPlaceholderText("OpenAI API Key")
            try:
                self._set_ai_provider_ui_active("gpt")
            except Exception:
                pass
        elif eng == "Gemini":
            self.cmb_ai_model.addItems(["gemini-1.5-pro", "gemini-1.5-flash"])
            if hasattr(self, "ed_ai_api_key"):
                self.ed_ai_api_key.setEnabled(True)
                self.ed_ai_api_key.setPlaceholderText("Gemini API Key")
            try:
                self._set_ai_provider_ui_active("gemini")
            except Exception:
                pass
        else:
            self.cmb_ai_model.addItems(["Local Strategy Engine"])
            if hasattr(self, "ed_ai_api_key"):
                self.ed_ai_api_key.setEnabled(False)
                self.ed_ai_api_key.setPlaceholderText("API Key 불필요")
            try:
                self._set_ai_provider_ui_active("local")
            except Exception:
                pass

    def _on_test_connection_clicked(self):
        eng = ""
        model = ""
        try:
            eng = (self.cmb_ai_engine.currentText() or "").strip()
            model = (self.cmb_ai_model.currentText() or "").strip()
        except Exception:
            pass
        if eng == "OpenAI":
            print("[AITS] OpenAI connection test")
            try:
                if hasattr(self, "ed_ai_api_key") and hasattr(self, "ed_openai_key"):
                    self.ed_openai_key.setText(self.ed_ai_api_key.text())
                if hasattr(self, "ed_openai_model") and model:
                    idx = self.ed_openai_model.findData(model)
                    if idx >= 0:
                        self.ed_openai_model.setCurrentIndex(idx)
                self._on_test_gpt()
            except Exception:
                pass
            try:
                self._update_engine_status_box()
            except Exception:
                pass
            return
        if eng == "Gemini":
            print("[AITS] Gemini connection test")
            try:
                if hasattr(self, "ed_ai_api_key") and hasattr(self, "ed_openai_key"):
                    self.ed_openai_key.setText(self.ed_ai_api_key.text())
                self._on_test_gemini()
            except Exception:
                pass
            try:
                self._update_engine_status_box()
            except Exception:
                pass
            return
        print("[AITS] Basic AI connection test")
        try:
            self._on_test_local_ai()
        except Exception:
            pass
        try:
            self._update_engine_status_box()
        except Exception:
            pass

    # --- AITS Managed Pool / Market Explorer (Qt 테이블 골격, ag-Grid 스타일 상태·이벤트 분리) ---
    _AI_M_COL_LOCK = -1
    _AI_M_COL_ACTION = -1
    _MKT_COL_ADD = 4

    def _fmt_change_pct(self, rate: float) -> str:
        try:
            x = float(rate or 0.0)
            if -1.0 <= x <= 1.0:
                return f"{x * 100.0:.2f}%"
            return f"{x:.2f}%"
        except Exception:
            return "0.00%"

    def _set_selected_ai_pool_symbol(self, sym: str) -> None:
        try:
            s = (sym or "").strip()
            if s == getattr(self, "_selected_ai_pool_symbol", ""):
                return
            self._selected_ai_pool_symbol = s
            print(f"[AITS] detail selected symbol={self._selected_ai_pool_symbol}")
        except Exception:
            pass

    def _clear_layout_items_detach(self, layout) -> None:
        try:
            if layout is None:
                return
            while layout.count():
                item = layout.takeAt(0)
                if item is None:
                    continue
                w = item.widget()
                if w is not None:
                    try:
                        w.setParent(None)
                    except Exception:
                        pass
                    continue
                child = item.layout()
                if child is not None:
                    self._clear_layout_items_detach(child)
        except Exception:
            pass

    def _make_center_dashboard_card(self, title: str, body: QWidget | None = None) -> tuple[QFrame, QVBoxLayout]:
        card = QFrame()
        try:
            card.setProperty("centerDashCard", True)
            card.setStyleSheet(
                "QFrame[centerDashCard='true']{background:#ffffff;border:1px solid #d9dde3;border-radius:8px;}"
            )
            card.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Preferred)
        except Exception:
            pass
        lay = QVBoxLayout(card)
        try:
            lay.setContentsMargins(12, 10, 12, 10)
            lay.setSpacing(8)
        except Exception:
            pass
        title_lb = QLabel(str(title or "").strip())
        try:
            title_lb.setProperty("reasonTitle", True)
            title_lb.setStyleSheet(
                "font-size:12px;font-weight:900;color:#111827;background:transparent;border:none;letter-spacing:0px;"
            )
        except Exception:
            pass
        lay.addWidget(title_lb, 0)
        if body is not None:
            lay.addWidget(body, 1)
        return card, lay

    def _make_center_info_card(
        self,
        title: str,
        body: QWidget,
        *,
        icon_attr: str,
        title_attr: str,
        icon_text: str,
        bg: str,
        border: str,
        title_color: str,
        icon_bg: str,
        icon_color: str,
    ) -> tuple[QFrame, QVBoxLayout]:
        card = QFrame()
        try:
            card.setProperty("centerInfoCard", True)
            card.setStyleSheet(
                "QFrame[centerInfoCard='true']{"
                f"background:{bg};border:1px solid {border};border-radius:14px;"
                "}"
            )
            card.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Fixed)
        except Exception:
            pass
        lay = QVBoxLayout(card)
        try:
            lay.setContentsMargins(14, 12, 14, 12)
            lay.setSpacing(8)
        except Exception:
            pass

        header = QHBoxLayout()
        try:
            header.setContentsMargins(0, 0, 0, 0)
            header.setSpacing(8)
        except Exception:
            pass

        icon = getattr(self, icon_attr, None)
        if icon is None:
            icon = QLabel(icon_text)
            setattr(self, icon_attr, icon)
        title_lb = getattr(self, title_attr, None)
        if title_lb is None:
            title_lb = QLabel(title)
            setattr(self, title_attr, title_lb)

        try:
            icon.setText(icon_text)
            icon.setFixedSize(34, 34)
            icon.setAlignment(Qt.AlignmentFlag.AlignCenter)
            icon.setStyleSheet(
                "font-size:18px;font-weight:900;"
                f"color:{icon_color};background:{icon_bg};"
                "border:none;border-radius:10px;"
            )
            title_lb.setText(str(title or "").strip())
            title_lb.setAlignment(Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignLeft)
            title_lb.setStyleSheet(
                f"font-size:13px;font-weight:800;color:{title_color};"
                "background:transparent;border:none;"
            )
        except Exception:
            pass

        header.addWidget(icon, 0)
        header.addWidget(title_lb, 0)
        header.addStretch(1)
        lay.addLayout(header, 0)
        lay.addWidget(body, 1)
        return card, lay

