    def _get_center_symbol_context_text(self, row=None):
        """
        중앙 카드용 맥락 문자열. 전역 AI 상태보다 선택 종목·상세 라벨을 앞에 둔다.
        row가 없으면 빈 문자열(미선택 시 고정 브리핑 문구로 떨어지게).
        """
        try:
            if not isinstance(row, dict):
                return ""

            parts = []
            seen = set()

            def _add(s):
                t = str(s or "").strip()
                if not t or t == "—":
                    return
                if t in seen:
                    return
                seen.add(t)
                parts.append(t)

            for attr in ("lbl_ai_detail_status",):
                try:
                    w = getattr(self, attr, None)
                    if w is not None:
                        _add(w.text())
                except Exception:
                    pass

            _add(row.get("ai_reason_summary") or "")
            for key in ("ai_status", "status", "decision", "summary"):
                v = row.get(key, "")
                if isinstance(v, (list, tuple)):
                    v = " ".join(str(x).strip() for x in v if str(x).strip())
                else:
                    v = str(v or "").strip()
                _add(v)

            for key in ("reason", "next_action"):
                v = row.get(key)
                if isinstance(v, (list, tuple)):
                    for x in v:
                        _add(x)
                else:
                    _add(str(v or "").strip())

            try:
                w = getattr(self, "lbl_ai_detail_hint", None)
                if w is not None and w.isVisible():
                    _add(w.text())
            except Exception:
                pass

            try:
                st = getattr(self, "lbl_ai_status", None)
                if st is not None:
                    _add(st.text())
            except Exception:
                pass

            return "\n".join(parts).strip()
        except Exception:
            return ""

    def _build_center_briefing_lines(self, row=None):
        try:
            src = self._get_center_symbol_context_text(row)
            lines = [ln.strip() for ln in str(src or "").splitlines() if str(ln).strip()]
            if not lines:
                return (
                    "- 선택 종목 분석 데이터가 아직 충분하지 않습니다.\n"
                    "- 시장/거래량/상태를 추가 확인 중입니다.\n"
                    "- 상세 원문은 '원문 보기'에서 확인할 수 있습니다."
                )
            picked = []
            for ln in lines:
                x = ln.lstrip("-• ").strip() or ln
                if x not in picked:
                    picked.append(x)
                if len(picked) >= 3:
                    break
            return "\n".join(f"- {p}" for p in picked[:3])
        except Exception:
            return (
                "- 선택 종목 분석 정보를 정리하지 못했습니다.\n"
                "- 상세 원문은 '원문 보기'에서 확인할 수 있습니다.\n"
                "- 잠시 후 다시 확인해 주세요."
            )

    def _build_center_why_next(self, row=None):
        try:
            why_plain = []
            next_plain = []
            status = ""
            disp = ""

            if isinstance(row, dict):
                status = str(row.get("ai_status") or row.get("status") or "").strip()
                try:
                    disp = self._format_aits_user_state_text(status) if status else ""
                except Exception:
                    disp = status or ""

                reason = row.get("reason", "")
                if isinstance(reason, (list, tuple)):
                    for x in reason:
                        t = str(x).strip()
                        if t:
                            why_plain.append(t)
                else:
                    for x in str(reason or "").splitlines():
                        t = x.strip()
                        if t:
                            why_plain.append(t)

                summary = row.get("summary", "")
                if isinstance(summary, (list, tuple)):
                    for x in summary:
                        t = str(x).strip()
                        if t:
                            why_plain.append(t)
                else:
                    for x in str(summary or "").splitlines():
                        t = x.strip()
                        if t:
                            why_plain.append(t)

                rs_sum = str(row.get("ai_reason_summary") or "").strip()
                if rs_sum:
                    for p in [x.strip() for x in rs_sum.replace("，", ",").split(",") if x.strip()]:
                        if p not in why_plain:
                            why_plain.append(p)

                na = row.get("next_action", "")
                if isinstance(na, (list, tuple)):
                    for x in na:
                        t = str(x).strip()
                        if t:
                            next_plain.append(t)
                else:
                    for x in str(na or "").splitlines():
                        t = x.strip()
                        if t:
                            next_plain.append(t)

                dec = str(row.get("decision", "") or "").strip()
                if dec:
                    next_plain.append(f"현재 판단 기준: {dec}")

            why_pick = []
            for w in why_plain:
                if w not in why_pick:
                    why_pick.append(w)
                if len(why_pick) >= 2:
                    break

            if len(why_pick) < 2:
                src = self._get_center_symbol_context_text(row if isinstance(row, dict) else None)
                for x in [ln.strip() for ln in src.splitlines() if ln.strip()]:
                    x = x.lstrip("-• ").strip()
                    if x and x not in why_pick:
                        why_pick.append(x)
                    if len(why_pick) >= 2:
                        break

            if not why_pick:
                why_pick = ["이유 정보를 정리하지 못했습니다."]
            elif len(why_pick) < 2:
                why_pick.append("RSI·거래량·추세 재확인")

            next_pick = []
            for n in next_plain:
                if n not in next_pick:
                    next_pick.append(n)
                if len(next_pick) >= 2:
                    break

            if len(next_pick) < 2:
                s = (disp or status or "").lower()
                u = f"{status} {disp}".upper()
                if ("보유" in (disp or status)) or ("hold" in s) or ("HOLD" in u):
                    next_pick = ["보유 유지 중", "익절/손절 기준 재평가"]
                elif ("매도" in (disp or status)) or ("sell" in s) or ("exit" in s):
                    next_pick = ["청산 조건 검토 중", "가격/리스크 재평가"]
                elif ("진입" in (disp or status)) or ("buy" in s) or ("ready" in s):
                    next_pick = ["진입 조건 확인 중", "거래량/추세 재평가"]
                else:
                    next_pick = ["추가 데이터 확인 중", "다음 판단을 준비 중"]

            why_txt = "\n".join(f"- {w}" for w in why_pick[:2])
            next_txt = "\n".join(f"- {n}" for n in next_pick[:2])
            return why_txt, next_txt
        except Exception:
            return "- 이유 정보를 정리하지 못했습니다.", "- 다음 행동 정보를 정리하지 못했습니다."

    def _append_aits_recent_log(self, sym: str, message: str) -> None:
        try:
            from datetime import datetime

            sym = (sym or "").strip()
            msg = (message or "").strip()
            if not msg:
                return
            st_key = f"{sym}|{msg}"
            if getattr(self, "_aits_last_detail_log_sym_status", "") == st_key:
                return
            self._aits_last_detail_log_sym_status = st_key
            ts = datetime.now().strftime("%H:%M")
            line = f"{ts} {sym + ' ' if sym else ''}{msg}".strip()
            buf = getattr(self, "_aits_recent_logs", None)
            if not isinstance(buf, list):
                buf = []
            buf.append(line)
            self._aits_recent_logs = buf[-5:]
        except Exception:
            pass

    def _sync_recent_log_label(self) -> None:
        lb = getattr(self, "lbl_ai_recent_log", None)
        bar = getattr(self, "lbl_ai_recent_log_bar", None)
        if lb is None and bar is None:
            return
        buf = getattr(self, "_aits_recent_logs", None) or []
        raw_text = ""
        latest = ""
        if buf:
            raw_text = "\n".join(str(x or "").strip() for x in buf if str(x or "").strip())
            latest = str(buf[-1] or "").strip()
        else:
            try:
                jh = getattr(self, "lbl_ai_detail_judgment_header", None)
                jt = jh.text() if jh is not None else "—"
            except Exception:
                jt = "—"
            from datetime import datetime

            latest = f"{datetime.now().strftime('%H:%M')} {jt}"
            raw_text = latest
        try:
            lines = [ln.strip() for ln in str(latest or raw_text or "").splitlines() if ln.strip()]
            if lines:
                latest = lines[-1]
            latest = str(latest or "—")
            latest = latest.replace("<br>", " ").replace("<br/>", " ").replace("<br />", " ")
            if "<" in latest and ">" in latest:
                try:
                    import re

                    latest = re.sub(r"<[^>]+>", "", latest)
                except Exception:
                    latest = latest.replace("<", " ").replace(">", " ")
            latest = " ".join(str(latest or "—").replace("\n", " ").replace("\t", " ").split())
            if lb is not None:
                lb.setVisible(False)
                lb.setText(raw_text or latest or "—")
            target = bar if bar is not None else lb
            if target is not None:
                target.setTextFormat(Qt.TextFormat.PlainText)
                target.setWordWrap(False)
                target.setAlignment(Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignLeft)
                target.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Fixed)
                target.setMinimumHeight(24)
                target.setMaximumHeight(24)
                target.setTextInteractionFlags(Qt.TextInteractionFlag.NoTextInteraction)
                target.setStyleSheet(
                    "font-size:12px;font-weight:500;color:#111827;background:transparent;border:none;"
                )
                target.setText(latest or "—")
            print(f"[AITS] live log synced: {latest or '—'}")
        except Exception:
            pass

