    def _update_market_price_history(self) -> None:
        try:
            for r in self.market_all_rows or []:
                sym = (r.get("symbol") or "").strip()
                if not sym:
                    continue
                try:
                    price = float(r.get("price") or 0.0)
                except Exception:
                    continue
                if price <= 0:
                    continue
                hist = self._market_price_history.setdefault(sym, [])
                hist.append(price)
                if len(hist) > 60:
                    del hist[:-60]
            print(f"[AITS] price history updated symbols={len(self._market_price_history)}")
        except Exception:
            pass

    def _fetch_upbit_minute_candles(self, symbol: str, unit: int = 1, count: int = 50) -> list[dict]:
        _m = {1: "1m", 5: "5m", 60: "60m"}.get(int(unit), "1m")
        return self._fetch_upbit_candles(symbol, _m, count)

    def _fetch_upbit_candles(self, symbol: str, tf: str = "1m", count: int = 50) -> list[dict]:
        try:
            sym = (symbol or "").strip()
            if not sym:
                return []
            import requests

            _tf = (tf or "1m").strip()
            if _tf in ("1d", "day", "daily"):
                url = "https://api.upbit.com/v1/candles/days"
            elif _tf in ("week", "1w", "weekly"):
                url = "https://api.upbit.com/v1/candles/weeks"
            elif _tf in ("month", "1mo", "mon"):
                url = "https://api.upbit.com/v1/candles/months"
            elif _tf == "5m":
                url = "https://api.upbit.com/v1/candles/minutes/5"
            elif _tf in ("30m", "minute30", "30"):
                url = "https://api.upbit.com/v1/candles/minutes/30"
            elif _tf == "15m":
                url = "https://api.upbit.com/v1/candles/minutes/15"
            elif _tf == "240m":
                url = "https://api.upbit.com/v1/candles/minutes/240"
            elif _tf == "60m":
                url = "https://api.upbit.com/v1/candles/minutes/60"
            elif _tf == "1m":
                url = "https://api.upbit.com/v1/candles/minutes/1"
            else:
                url = "https://api.upbit.com/v1/candles/minutes/1"
            resp = requests.get(
                url,
                params={"market": sym, "count": int(count)},
                timeout=5,
            )
            resp.raise_for_status()
            data = resp.json()
            if not isinstance(data, list):
                return []
            return data
        except Exception:
            return []

