    def _format_aits_coin_display_name(self, symbol_text: str):
        try:
            raw = str(symbol_text or "").strip()
            if not raw:
                return ""

            short_symbol = raw
            if raw.upper().startswith("KRW-"):
                short_symbol = raw.split("-", 1)[1].strip().upper()
            else:
                short_symbol = raw.upper()

            ko = self._get_aits_korean_coin_name(short_symbol)
            if ko:
                return f"{short_symbol} {ko}"
            return short_symbol
        except Exception:
            try:
                return str(symbol_text or "")
            except Exception:
                return ""

    def _merge_aits_symbol_and_name(self, symbol_text: str, name_text: str = ""):
        try:
            raw = str(symbol_text or "").strip().upper()
            if raw.startswith("KRW-"):
                raw = raw.split("-", 1)[1].strip().upper()

            name_val = str(name_text or "").strip()
            ko_fallback = self._get_aits_korean_coin_name(raw)

            if not name_val:
                if ko_fallback:
                    return f"{raw} {ko_fallback}"
                return raw

            if name_val.upper() == raw:
                if ko_fallback:
                    return f"{raw} {ko_fallback}"
                return raw

            if ko_fallback and name_val == ko_fallback:
                return f"{raw} {ko_fallback}"

            return f"{raw} {name_val}"
        except Exception:
            try:
                return str(symbol_text or "")
            except Exception:
                return ""

    def _normalize_aits_market_symbol(self, symbol_text: str):
        try:
            s = str(symbol_text or "").strip().upper()
            if not s:
                return ""

            if s.startswith("KRW-"):
                return s

            return f"KRW-{s}"
        except Exception:
            try:
                return str(symbol_text or "").strip()
            except Exception:
                return ""

    def _format_aits_user_kind_text(self, kind_text):
        try:
            k = str(kind_text or "").strip()
            kl = k.lower()

            if kl == "ai":
                return "AI"
            if kl == "user":
                return "사용자 추가"
            if not k:
                return ""
            return k
        except Exception:
            try:
                return str(kind_text or "")
            except Exception:
                return ""

    def _format_aits_user_state_text(self, state_text):
        try:
            s = str(state_text or "").strip()
            sl = s.lower()

            if "drop" in sl:
                return "관망"
            if "watch" in sl:
                return "조건 대기"
            if "hold" in sl:
                return "보유 관찰"
            if "buy" in sl:
                return "진입 검토"
            if "sell" in sl:
                return "매도 검토"
            if "lock" in sl:
                return "잠금"
            if not s:
                return ""
            return s
        except Exception:
            try:
                return str(state_text or "")
            except Exception:
                return ""

    def _build_ai_strategy_cards(
        self, ai_reason_text: str, ai_state_text: str = "", ai_score_text: str = ""
    ):
        try:
            payload = self._get_aits_final_explanation_payload()
            payload_decision = str(payload.get("decision", "") or "").strip()
            payload_reasons = list(payload.get("reason", []) or [])

            reason = str(ai_reason_text or "").strip()
            state = str(ai_state_text or "").strip()
            score = str(ai_score_text or "").strip()

            cards = []

            if payload_decision:
                cards.append((payload_decision, "AI 최종 판단 기준"))
            for r in payload_reasons[:2]:
                rt = str(r).strip()
                if rt:
                    cards.append((rt, "AI 판단 근거"))

            state_l = state.lower()

            if "drop" in state_l:
                cards.append(("관망 우세", "현재 조건에서는 즉시 진입보다 제외/대기 가능성이 높음"))
            elif "watch" in state_l:
                cards.append(("조건 대기", "추가 신호 확인 전까지 관찰 우세"))
            elif "hold" in state_l:
                cards.append(("보유 관찰", "현재 포지션 유지 여부를 확인 중"))
            elif "buy" in state_l:
                cards.append(("진입 검토", "조건 충족 시 진입 가능성 확인 중"))
            elif "sell" in state_l:
                cards.append(("매도 검토", "조건 충족 시 정리·매도 시나리오를 확인 중"))

            if "거래대금 부족" in reason:
                cards.append(("유동성 주의", "체결/추격 매수보다 대기 가능성이 높음"))

            if "시장 평균 약세" in reason:
                cards.append(("시장 약세 반영", "보수적 대응이 우선될 가능성"))

            if "보수" in reason:
                cards.append(("보수 전략", "분할 접근 또는 추가 확인 후 대응"))

            if score:
                cards.append((f"AI 점수 {score}", "현재 평가 점수 기준 상태 유지"))

            cards = cards[:3]

            while len(cards) < 3:
                cards.append(("", ""))

            return cards

        except Exception:
            return [("", ""), ("", ""), ("", "")]

