    def _get_aits_basic_config_ssot(self) -> dict:
        """
        Basic 설정의 단일 기준(SSOT)을 반환한다.
        현재는 UI에서 즉시 수집한 값을 기준으로 하고,
        실패 시 기존 basic_ai_settings를 하위 호환용으로 보정 사용한다.
        """
        try:
            cfg = self._collect_aits_basic_engine_settings()
            if isinstance(cfg, dict) and cfg:
                return cfg
        except Exception:
            pass

        legacy = {}
        try:
            legacy = getattr(self, "basic_ai_settings", None) or {}
        except Exception:
            legacy = {}

        if not isinstance(legacy, dict):
            legacy = {}

        def _norm_risk(v):
            s = str(v).strip()
            if s == "보수적":
                return "conservative"
            if s == "공격적":
                return "aggressive"
            return "neutral"

        def _norm_level3(v):
            s = str(v).strip()
            if s == "낮음":
                return "low"
            if s == "높음":
                return "high"
            return "medium"

        def _norm_sell(v):
            s = str(v).strip()
            if s == "느림":
                return "slow"
            if s == "빠름":
                return "fast"
            return "medium"

        def _norm_trend(v):
            s = str(v).strip()
            if s == "약함":
                return "weak"
            if s == "강함":
                return "strong"
            return "medium"

        _tp = float(legacy.get("take_profit_pct", legacy.get("target_profit_pct", 3.5)) or 3.5)
        _min_krw = int(legacy.get("min_trade_value_krw", legacy.get("min_volume", 100000000)) or 100000000)
        _max_conc = int(legacy.get("max_concurrent_buys", legacy.get("max_new_entries", 1)) or 1)
        _risk_kr = str(legacy.get("risk_profile_kr", legacy.get("risk_mode", "중립"))).strip() or "중립"
        _sel_kr = str(
            legacy.get("selection_strength_kr", legacy.get("selection_strength", "보통"))
        ).strip() or "보통"
        _buy_kr = str(legacy.get("buy_sensitivity_kr", legacy.get("buy_sensitivity", "보통"))).strip() or "보통"
        _sell_kr = str(legacy.get("sell_sensitivity_kr", legacy.get("sell_sensitivity", "보통"))).strip() or "보통"
        _trend_kr = str(
            legacy.get("trend_filter_strength_kr", legacy.get("trend_filter", "보통"))
        ).strip() or "보통"
        _dec_kr = str(legacy.get("decision_speed_kr", legacy.get("decision_speed", "보통"))).strip() or "보통"

        return {
            "engine_mode": "basic",
            "ui_labels_kr": {
                "운용 성향": _risk_kr,
                "종목 선별 강도": _sel_kr,
                "최대 보유 종목 수": legacy.get("max_positions", 5),
                "목표 수익률 (%)": _tp,
                "손절 기준 (%)": legacy.get("stop_loss_pct", 1.5),
                "최대 보유 시간 (분)": legacy.get("max_hold_minutes", legacy.get("max_hold_time", 90)),
                "매수 민감도": _buy_kr,
                "매도 민감도": _sell_kr,
                "분할 매수": legacy.get("split_buy_enabled", legacy.get("split_buy", True)),
                "분할 매도": legacy.get("split_sell_enabled", legacy.get("split_sell", True)),
                "최소 거래대금 (원)": _min_krw,
                "추세 필터": _trend_kr,
                "하락장 회피": legacy.get("avoid_bear_market", True),
                "급락 회피": legacy.get("avoid_sharp_drop", legacy.get("avoid_sudden_drop", True)),
                "과열 종목 제외": legacy.get("exclude_overheated", True),
                "AI 진입 기준 점수": legacy.get("entry_score_threshold", 60),
                "AI 청산 기준 점수": legacy.get("exit_score_threshold", 45),
                "AI 판단 속도": _dec_kr,
                "재진입 제한 시간 (분)": legacy.get(
                    "reentry_cooldown_minutes", legacy.get("reentry_cooldown_min", 30)
                ),
                "동시 매수 제한 수": _max_conc,
            },
            "risk_profile": _norm_risk(_risk_kr),
            "selection_strength": _norm_level3(_sel_kr),
            "max_positions": int(legacy.get("max_positions", 5) or 5),
            "take_profit_pct": _tp,
            "stop_loss_pct": float(legacy.get("stop_loss_pct", 1.5) or 1.5),
            "max_hold_minutes": int(
                legacy.get("max_hold_minutes", legacy.get("max_hold_time", 90)) or 90
            ),
            "buy_sensitivity": _norm_level3(_buy_kr),
            "sell_sensitivity": _norm_sell(_sell_kr),
            "split_buy_enabled": bool(legacy.get("split_buy_enabled", legacy.get("split_buy", True))),
            "split_sell_enabled": bool(legacy.get("split_sell_enabled", legacy.get("split_sell", True))),
            "min_trade_value_krw": _min_krw,
            "trend_filter_strength": _norm_trend(_trend_kr),
            "avoid_bear_market": bool(legacy.get("avoid_bear_market", True)),
            "avoid_sharp_drop": bool(legacy.get("avoid_sharp_drop", legacy.get("avoid_sudden_drop", True))),
            "exclude_overheated": bool(legacy.get("exclude_overheated", True)),
            "entry_score_threshold": int(legacy.get("entry_score_threshold", 60) or 60),
            "exit_score_threshold": int(legacy.get("exit_score_threshold", 45) or 45),
            "decision_speed_kr": _dec_kr,
            "decision_speed": _norm_sell(_dec_kr),
            "reentry_cooldown_minutes": int(
                legacy.get("reentry_cooldown_minutes", legacy.get("reentry_cooldown_min", 30)) or 30
            ),
            "max_concurrent_buys": _max_conc,
        }

    def _sync_legacy_basic_ai_settings_from_ssot(self) -> dict:
        """
        basic_config SSOT를 기존 basic_ai_settings cache 형태로 동기화한다.
        이번 단계에서는 하위 호환용 cache 유지 목적이다.
        """
        cfg = self._get_aits_basic_config_ssot()
        legacy = {
            "risk_profile": cfg.get("risk_profile", "neutral"),
            "risk_profile_kr": (cfg.get("ui_labels_kr") or {}).get("운용 성향", "중립"),
            "selection_strength": cfg.get("selection_strength", "medium"),
            "selection_strength_kr": (cfg.get("ui_labels_kr") or {}).get("종목 선별 강도", "보통"),
            "max_positions": cfg.get("max_positions", 5),
            "take_profit_pct": cfg.get("take_profit_pct", 3.5),
            "stop_loss_pct": cfg.get("stop_loss_pct", 1.5),
            "max_hold_minutes": cfg.get("max_hold_minutes", 90),
            "buy_sensitivity": cfg.get("buy_sensitivity", "medium"),
            "buy_sensitivity_kr": (cfg.get("ui_labels_kr") or {}).get("매수 민감도", "보통"),
            "sell_sensitivity": cfg.get("sell_sensitivity", "medium"),
            "sell_sensitivity_kr": (cfg.get("ui_labels_kr") or {}).get("매도 민감도", "보통"),
            "split_buy_enabled": cfg.get("split_buy_enabled", True),
            "split_sell_enabled": cfg.get("split_sell_enabled", True),
            "min_volume": cfg.get("min_trade_value_krw", 100000000),
            "min_trade_value_krw": cfg.get("min_trade_value_krw", 100000000),
            "trend_filter_strength": cfg.get("trend_filter_strength", "medium"),
            "trend_filter_strength_kr": (cfg.get("ui_labels_kr") or {}).get("추세 필터", "보통"),
            "avoid_bear_market": cfg.get("avoid_bear_market", True),
            "avoid_sharp_drop": cfg.get("avoid_sharp_drop", True),
            "exclude_overheated": cfg.get("exclude_overheated", True),
            "entry_score_threshold": cfg.get("entry_score_threshold", 60),
            "exit_score_threshold": cfg.get("exit_score_threshold", 45),
            "decision_speed": cfg.get("decision_speed", "medium"),
            "decision_speed_kr": cfg.get(
                "decision_speed_kr",
                (cfg.get("ui_labels_kr") or {}).get("AI 판단 속도", "보통"),
            ),
            "reentry_cooldown_minutes": cfg.get("reentry_cooldown_minutes", 30),
            "max_new_entries": cfg.get("max_concurrent_buys", 1),
            "max_concurrent_buys": cfg.get("max_concurrent_buys", 1),
        }
        ui_kr = cfg.get("ui_labels_kr") or {}
        legacy["risk_mode"] = str(ui_kr.get("운용 성향", legacy.get("risk_profile_kr", "중립")))
        legacy["selection_strength"] = str(ui_kr.get("종목 선별 강도", "보통"))
        legacy["buy_sensitivity"] = str(ui_kr.get("매수 민감도", "보통"))
        legacy["sell_sensitivity"] = str(ui_kr.get("매도 민감도", "보통"))
        legacy["trend_filter"] = str(ui_kr.get("추세 필터", "보통"))
        legacy["decision_speed"] = str(
            legacy.get("decision_speed_kr") or ui_kr.get("AI 판단 속도", "보통")
        )
        legacy["split_buy"] = bool(legacy.get("split_buy_enabled", True))
        legacy["split_sell"] = bool(legacy.get("split_sell_enabled", True))
        legacy["max_hold_time"] = int(legacy.get("max_hold_minutes", 90) or 90)
        legacy["reentry_cooldown_min"] = int(legacy.get("reentry_cooldown_minutes", 30) or 30)
        legacy["avoid_sudden_drop"] = bool(legacy.get("avoid_sharp_drop", True))
        _tp = float(legacy.get("take_profit_pct", 3.5) or 3.5)
        legacy["target_profit_pct"] = _tp
        self.basic_ai_settings = legacy
        return legacy

    def _call_aits_gemini_reco(self, prompt_text: str) -> dict:
        """
        Gemini 메인 reco 호출.
        반환:
        {
            "ok": bool,
            "text": str,
            "error": str,
            "model": str,
        }
        """
        import requests

        api_key = ""
        try:
            api_key = str(getattr(self, "ed_gemini_key", None).text() or "").strip()
        except Exception:
            api_key = ""
        if not api_key or (len(api_key) > 0 and api_key.startswith("•")):
            return {"ok": False, "text": "", "error": "Gemini API 키 없음", "model": ""}

        model_name = "gemini-1.5-flash"
        try:
            obj = getattr(self, "cmb_gemini_model", None)
            if obj is not None and hasattr(obj, "currentText"):
                v = str(obj.currentText() or "").strip().replace(" ", "")
                if v:
                    model_name = v
        except Exception:
            pass

        url = (
            "https://generativelanguage.googleapis.com/v1beta/models/"
            f"{model_name}:generateContent"
        )
        headers = {"Content-Type": "application/json"}
        payload = {"contents": [{"parts": [{"text": prompt_text}]}]}

        try:
            resp = requests.post(
                url, headers=headers, params={"key": api_key}, json=payload, timeout=90
            )
        except Exception as e:
            return {"ok": False, "text": "", "error": f"Gemini 요청 실패: {e}", "model": model_name}

        if resp.status_code != 200:
            return {
                "ok": False,
                "text": "",
                "error": f"Gemini HTTP {resp.status_code}: {(resp.text or '')[:300]}",
                "model": model_name,
            }

        try:
            body = resp.json()
        except Exception:
            return {"ok": False, "text": "", "error": "Gemini JSON 파싱 실패", "model": model_name}

        text_out = ""
        try:
            candidates = body.get("candidates") or []
            if candidates:
                content = (candidates[0] or {}).get("content") or {}
                parts = content.get("parts") or []
                texts = []
                for p in parts:
                    if isinstance(p, dict) and p.get("text"):
                        texts.append(str(p.get("text")))
                text_out = "\n".join(texts).strip()
        except Exception:
            text_out = ""

        if not text_out:
            return {
                "ok": False,
                "text": "",
                "error": "Gemini 응답 본문 비어 있음",
                "model": model_name,
            }

        return {"ok": True, "text": text_out, "error": "", "model": model_name}

    def _run_aits_main_gpt_reco_and_publish(self) -> None:
        """
        실운용: STEP 41 프롬프트로 OpenAI 호출 후 ai.reco.updated 에 원문·rotation 포함 publish.
        app.services.ai_reco 는 raw 키를 보존하지 않으므로 eventbus 로만 전달한다.
        """
        now_ts = time.time()

        try:
            should_run, _why = self._should_run_aits_main_gpt_reco()
            if not should_run:
                return
        except Exception:
            pass

        def _fallback_reco_update_basic_engine():
            market_rows_fb = []
            positions_fb = []
            try:
                ctx_fb = self._build_aits_ai_decision_context()
                for qc in (ctx_fb.get("quick_candidates") or [])[:50]:
                    if not isinstance(qc, dict):
                        continue
                    sym = str(qc.get("symbol") or "").strip()
                    if not sym:
                        continue
                    row = {"symbol": sym}
                    try:
                        if "change_pct" in qc:
                            row["change_pct"] = qc.get("change_pct")
                        tv = qc.get("trade_value")
                        if tv is not None:
                            row["trade_value"] = float(tv)
                    except Exception:
                        pass
                    market_rows_fb.append(row)
                for pos in (getattr(self, "ai_managed_rows", []) or [])[:50]:
                    if not isinstance(pos, dict):
                        continue
                    psym = str(
                        pos.get("symbol") or pos.get("market") or ""
                    ).strip()
                    if not psym:
                        continue
                    prow = {"symbol": psym}
                    for k in (
                        "pnl_pct",
                        "profit_pct",
                        "unrealized_pnl_pct",
                        "change_pct",
                        "change_rate",
                    ):
                        if pos.get(k) is None:
                            continue
                        try:
                            prow[k] = float(pos.get(k))
                        except (TypeError, ValueError):
                            pass
                    positions_fb.append(prow)
            except Exception:
                pass
            try:
                self._log.info(
                    "[AITS][BasicFallback] GPT unavailable -> reco update with market_rows"
                )
            except Exception:
                pass
            try:
                _basic_cfg = {}
                try:
                    _basic_cfg = self._collect_aits_basic_engine_settings()
                except Exception:
                    _basic_cfg = {}
                ai_reco.update(
                    payload={
                        "use_basic_engine": True,
                        "basic_fallback": True,
                        "market_rows": market_rows_fb,
                        "positions": positions_fb,
                        "basic_config": _basic_cfg,
                    },
                    from_boot=True,
                )
            except Exception:
                pass

        try:
            prov = (
                getattr(self, "cb_ai_provider", None)
                and self.cb_ai_provider.currentText()
                or ""
            ).strip().lower()

            engine_mode = "gpt"
            try:
                engine_mode = self._get_aits_selected_engine_mode()
            except Exception:
                engine_mode = "gpt"

            if engine_mode == "basic":
                try:
                    if hasattr(self, "_log") and self._log:
                        self._log.info(
                            "[AITS][EngineMode] basic selected -> direct basic engine reco"
                        )
                except Exception:
                    pass

                try:
                    basic_payload = self._build_aits_basic_engine_payload_for_reco()
                    try:
                        basic_payload["basic_config"] = (
                            self._collect_aits_basic_engine_settings()
                        )
                    except Exception:
                        basic_payload["basic_config"] = {}
                    ai_reco.update(
                        payload=basic_payload,
                        from_boot=True,
                    )
                except Exception:
                    try:
                        _basic_cfg_ex = {}
                        try:
                            _basic_cfg_ex = self._collect_aits_basic_engine_settings()
                        except Exception:
                            _basic_cfg_ex = {}
                        ai_reco.update(
                            payload={
                                "use_basic_engine": True,
                                "basic_fallback": True,
                                "market_rows": [],
                                "positions": [],
                                "basic_config": _basic_cfg_ex,
                            },
                            from_boot=True,
                        )
                    except Exception:
                        pass
                return

            if engine_mode == "gemini":
                # [PATCH 5-4]
                # Gemini 선택 시 메인 reco를 실제 Gemini API로 호출한다.
                # 실패 시에만 기존 Basic fallback 경로로 내려간다.
                try:
                    if hasattr(self, "_log") and self._log:
                        self._log.info(
                            "[AITS][EngineMode] gemini selected -> live gemini reco path"
                        )
                except Exception:
                    pass

                try:
                    self._aits_main_reco_inflight = True
                    self._aits_main_reco_last_started_ts = now_ts
                    self._aits_main_reco_request_seq = (
                        int(getattr(self, "_aits_main_reco_request_seq", 0) or 0) + 1
                    )
                    current_seq = self._aits_main_reco_request_seq

                    ctx = self._build_aits_ai_decision_context()
                    prompt_text = ""
                    try:
                        prompt_text = (self._build_aits_ai_decision_prompt() or "").strip()
                    except Exception:
                        prompt_text = ""
                    if not prompt_text:
                        try:
                            prompt_text = json.dumps(ctx, ensure_ascii=False, indent=2)
                        except Exception:
                            prompt_text = str(ctx)
                    if not str(prompt_text).strip():
                        raise RuntimeError("Gemini용 프롬프트 생성 실패")

                    try:
                        current_fp = self._build_aits_reco_payload_fingerprint()
                    except Exception:
                        current_fp = ""

                    gemini_ret = self._call_aits_gemini_reco(prompt_text)
                    if not gemini_ret.get("ok"):
                        raise RuntimeError(gemini_ret.get("error") or "Gemini reco 실패")

                    ai_raw_text = str(gemini_ret.get("text") or "").strip()
                    if not ai_raw_text:
                        raise RuntimeError("Gemini 응답 텍스트 비어 있음")

                    g_model = str(gemini_ret.get("model") or "gemini-1.5-flash").strip()

                    self._aits_last_ai_raw_response = ai_raw_text

                    rotation_d: dict = {}
                    try:
                        srot = str(ai_raw_text or "").strip()
                        if srot.startswith("```"):
                            lines = srot.split("\n")
                            if len(lines) >= 3 and lines[-1].strip() == "```":
                                srot = "\n".join(lines[1:-1]).strip()
                            elif len(lines) >= 2:
                                srot = "\n".join(lines[1:]).strip()
                                if srot.endswith("```"):
                                    srot = srot[:-3].strip()
                        pj = json.loads(srot)
                        if isinstance(pj, dict) and isinstance(pj.get("rotation"), dict):
                            rotation_d = pj.get("rotation") or {}
                    except Exception:
                        pass

                    pr = self._parse_aits_ai_response(ai_raw_text)
                    decision = str(pr.get("decision") or "").strip()
                    reasons = pr.get("reason") or []
                    if isinstance(reasons, str):
                        reasons = [reasons] if reasons else []

                    items: list[dict] = []
                    for qc in (ctx.get("quick_candidates") or [])[:12]:
                        if not isinstance(qc, dict):
                            continue
                        sym = str(qc.get("symbol") or "").strip()
                        if not sym:
                            continue
                        items.append(
                            {
                                "symbol": sym,
                                "title": str(qc.get("display_name") or sym).strip(),
                            }
                        )

                    reason_code = " · ".join(str(x) for x in reasons[:5] if str(x).strip())[
                        :2000
                    ]

                    reco_payload = {
                        "ok": True,
                        "source": "gemini",
                        "fallback": False,
                        "items": items,
                        "decision_summary": decision[:500] if decision else "AITS 판단",
                        "reason_code": reason_code,
                        "raw_ai_response": ai_raw_text,
                        "ai_raw_text": ai_raw_text,
                        "rotation": rotation_d,
                        "actual_engine": f"gemini-{g_model}",
                        "selected_engine": "gemini",
                    }

                    try:
                        latest_seq = int(getattr(self, "_aits_main_reco_request_seq", 0) or 0)
                        if current_seq < latest_seq:
                            return
                    except Exception:
                        pass

                    try:
                        self._aits_main_reco_latest_applied_seq = current_seq
                        self._aits_main_reco_latest_payload_fp = current_fp
                        self._aits_main_reco_last_completed_ts = time.time()
                    except Exception:
                        pass

                    try:
                        self._last_response_provider = "gemini"
                    except Exception:
                        pass

                    try:
                        self._gpt_status_stage = "ready"
                    except Exception:
                        pass

                    try:
                        if hasattr(self, "lbl_aits_ai_engine_status") and self.lbl_aits_ai_engine_status is not None:
                            self.lbl_aits_ai_engine_status.setText(
                                "AITS AI 상태: Gemini 응답 정상"
                            )
                            self._apply_aits_ai_engine_status_line_style(
                                "AITS AI 상태: Gemini 응답 정상"
                            )
                    except Exception:
                        pass

                    try:
                        self._update_top_badge()
                    except Exception:
                        pass

                    try:
                        self._update_engine_ui_ssot()
                    except Exception:
                        pass

                    eventbus.publish("ai.reco.updated", reco_payload)
                    try:
                        self._log.info(
                            "[AITS-RECO-MAIN][Gemini] published ok=1 items=%s",
                            len(items),
                        )
                    except Exception:
                        pass
                    return

                except Exception as e:
                    try:
                        if hasattr(self, "_log") and self._log:
                            self._log.warning("[AITS][GeminiReco] fallback to basic | %s", e)
                    except Exception:
                        pass

                    try:
                        self._gpt_status_stage = "waiting"
                    except Exception:
                        pass

                    try:
                        if hasattr(self, "lbl_aits_ai_engine_status") and self.lbl_aits_ai_engine_status is not None:
                            self.lbl_aits_ai_engine_status.setText(
                                "AITS AI 상태: Gemini 응답 대기 중"
                            )
                            self._apply_aits_ai_engine_status_line_style(
                                "AITS AI 상태: Gemini 응답 대기 중"
                            )
                    except Exception:
                        pass

                    try:
                        self._update_top_badge()
                    except Exception:
                        pass

                    try:
                        basic_payload = self._build_aits_basic_engine_payload_for_reco()
                        try:
                            basic_payload["basic_config"] = (
                                self._collect_aits_basic_engine_settings()
                            )
                        except Exception:
                            basic_payload["basic_config"] = {}
                        basic_payload["engine_mode"] = "gemini"
                        basic_payload["reason"] = f"Gemini fallback: {e}"
                        ai_reco.update(
                            payload=basic_payload,
                            from_boot=True,
                        )
                    except Exception:
                        try:
                            _basic_cfg_ex = {}
                            try:
                                _basic_cfg_ex = self._collect_aits_basic_engine_settings()
                            except Exception:
                                _basic_cfg_ex = {}
                            ai_reco.update(
                                payload={
                                    "use_basic_engine": True,
                                    "basic_fallback": True,
                                    "market_rows": [],
                                    "positions": [],
                                    "engine_mode": "gemini",
                                    "basic_config": _basic_cfg_ex,
                                    "reason": f"Gemini fallback: {e}",
                                },
                                from_boot=True,
                            )
                        except Exception:
                            pass
                    return

            if prov != "gpt" and engine_mode == "gpt":
                _fallback_reco_update_basic_engine()
                return

            api_key = ""
            try:
                st = getattr(self._settings, "strategy", None) if getattr(self, "_settings", None) else None
                if st is not None:
                    api_key = (getattr(st, "ai_openai_api_key", "") or "").strip()
                if not api_key and hasattr(self, "ed_openai_key"):
                    api_key = (self.ed_openai_key.text() or "").strip()
            except Exception:
                pass
            if not api_key or api_key.startswith("•"):
                _fallback_reco_update_basic_engine()
                return

            model = ""
            if hasattr(self, "cb_custom_model") and self.cb_custom_model.isChecked():
                custom_model = (self.inp_custom_model.text() or "").strip()
                if custom_model:
                    model = custom_model
            if not model and hasattr(self, "ed_openai_model"):
                model_id = self.ed_openai_model.currentData()
                if model_id:
                    model = model_id
                else:
                    current_text = (self.ed_openai_model.currentText() or "").strip()
                    for model_info in getattr(self, "KMTS_GPT_MODELS", []):
                        if model_info.get("label") == current_text:
                            model = model_info.get("id", "")
                            break
            if not model:
                model = "gpt-4o-mini"

            self._aits_main_reco_inflight = True
            self._aits_main_reco_last_started_ts = now_ts
            self._aits_main_reco_request_seq = (
                int(getattr(self, "_aits_main_reco_request_seq", 0) or 0) + 1
            )
            current_seq = self._aits_main_reco_request_seq

            try:
                self._aits_last_ai_prompt = self._build_aits_ai_decision_prompt()
            except Exception:
                pass

            try:
                current_fp = self._build_aits_reco_payload_fingerprint()
            except Exception:
                current_fp = ""

            try:
                messages = self._build_aits_ai_messages()
            except Exception:
                messages = [
                    {"role": "user", "content": self._build_aits_ai_decision_prompt()},
                ]

            import requests

            url = "https://api.openai.com/v1/chat/completions"
            headers = {"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"}
            body = {
                "model": model,
                "messages": messages,
                "max_tokens": 1200,
            }
            resp = requests.post(url, headers=headers, json=body, timeout=90)
            if resp.status_code != 200:
                try:
                    self._log.warning(
                        "[AITS-RECO-MAIN] http=%s", int(resp.status_code)
                    )
                except Exception:
                    pass
                _fallback_reco_update_basic_engine()
                return

            try:
                rj = resp.json()
            except Exception:
                rj = {}
            choices = rj.get("choices") or []
            ai_raw_text = ""
            if choices and isinstance(choices[0], dict):
                delta = choices[0].get("message") or choices[0].get("delta") or {}
                ai_raw_text = (delta.get("content") or "").strip()

            if not str(ai_raw_text or "").strip():
                _fallback_reco_update_basic_engine()
                return

            self._aits_last_ai_raw_response = ai_raw_text

            rotation_d: dict = {}
            try:
                srot = str(ai_raw_text or "").strip()
                if srot.startswith("```"):
                    lines = srot.split("\n")
                    if len(lines) >= 3 and lines[-1].strip() == "```":
                        srot = "\n".join(lines[1:-1]).strip()
                    elif len(lines) >= 2:
                        srot = "\n".join(lines[1:]).strip()
                        if srot.endswith("```"):
                            srot = srot[:-3].strip()
                pj = json.loads(srot)
                if isinstance(pj, dict) and isinstance(pj.get("rotation"), dict):
                    rotation_d = pj.get("rotation") or {}
            except Exception:
                pass

            pr = self._parse_aits_ai_response(ai_raw_text)
            decision = str(pr.get("decision") or "").strip()
            reasons = pr.get("reason") or []
            if isinstance(reasons, str):
                reasons = [reasons] if reasons else []

            ctx = self._build_aits_ai_decision_context()
            items: list[dict] = []
            for qc in (ctx.get("quick_candidates") or [])[:12]:
                if not isinstance(qc, dict):
                    continue
                sym = str(qc.get("symbol") or "").strip()
                if not sym:
                    continue
                items.append(
                    {
                        "symbol": sym,
                        "title": str(qc.get("display_name") or sym).strip(),
                    }
                )

            reason_code = " · ".join(str(x) for x in reasons[:5] if str(x).strip())[
                :2000
            ]

            reco_payload = {
                "ok": True,
                "source": "gpt",
                "fallback": False,
                "items": items,
                "decision_summary": decision[:500] if decision else "AITS 판단",
                "reason_code": reason_code,
                "raw_ai_response": ai_raw_text,
                "ai_raw_text": ai_raw_text,
                "rotation": rotation_d,
                "actual_engine": f"gpt-{model}",
                "selected_engine": "gpt",
            }
            reco_payload["source"] = "gpt"

            try:
                latest_seq = int(getattr(self, "_aits_main_reco_request_seq", 0) or 0)
                if current_seq < latest_seq:
                    return
            except Exception:
                pass

            try:
                self._aits_main_reco_latest_applied_seq = current_seq
                self._aits_main_reco_latest_payload_fp = current_fp
                self._aits_main_reco_last_completed_ts = time.time()
            except Exception:
                pass

            eventbus.publish("ai.reco.updated", reco_payload)
            try:
                self._log.info("[AITS-RECO-MAIN] published ok=1 items=%s", len(items))
            except Exception:
                pass
        except Exception:
            try:
                _fallback_reco_update_basic_engine()
            except Exception:
                pass
            try:
                self._log.warning("[AITS-RECO-MAIN] fail")
            except Exception:
                pass
        finally:
            try:
                self._aits_main_reco_inflight = False
            except Exception:
                pass

    def _apply_market_view_mode_button_state(self):
        try:
            mode = str(getattr(self, "_market_view_mode", "quick") or "quick").strip().lower()
            primary_style = (
                "QPushButton {"
                "padding:2px 10px;"
                "background:#eef6ff;"
                "border:1px solid #93c5fd;"
                "border-radius:10px;"
                "color:#1d4ed8;"
                "font-size:12px;"
                "font-weight:800;"
                "}"
                "QPushButton:hover {"
                "background:#f8fbff;"
                "border-color:#bfdbfe;"
                "}"
                "QPushButton:pressed { background:#dbeafe; }"
            )
            secondary_style = (
                "QPushButton {"
                "padding:2px 10px;"
                "background:#ffffff;"
                "border:1px solid #d7dee8;"
                "border-radius:10px;"
                "color:#475569;"
                "font-size:12px;"
                "font-weight:700;"
                "}"
                "QPushButton:hover {"
                "background:#f8fbff;"
                "border-color:#bfdbfe;"
                "}"
                "QPushButton:pressed { background:#dbeafe; }"
            )

            if mode == "all":
                self.btn_market_quick.setEnabled(True)
                self.btn_market_all.setEnabled(True)
                self.btn_market_quick.setStyleSheet(secondary_style)
                self.btn_market_all.setStyleSheet(primary_style)
            else:
                self.btn_market_quick.setEnabled(True)
                self.btn_market_all.setEnabled(True)
                self.btn_market_quick.setStyleSheet(primary_style)
                self.btn_market_all.setStyleSheet(secondary_style)
        except Exception:
            pass

    def _on_market_view_mode_quick(self):
        try:
            self._market_view_mode = "quick"
            self._set_market_filter("surge", refresh=False)
            self._apply_market_view_mode_button_state()
            self._refresh_market_all_table()
        except Exception:
            pass

    def _on_market_view_mode_all(self):
        try:
            self._market_view_mode = "all"
            self._set_market_filter("all", refresh=False)
            # 전체 보기 누른 시점에만 전체 캐시 확보
            self._ensure_market_all_rows()
            self._apply_market_view_mode_button_state()
            self._refresh_market_all_table()
        except Exception:
            pass

    def _get_market_display_limit(self) -> int:
        try:
            cmb = getattr(self, "cmb_market_limit", None)
            if cmb is not None:
                limit = int(cmb.currentData() or 50)
                if limit in (50, 250):
                    return limit
        except Exception:
            pass
        return 50

    def _on_market_limit_changed(self):
        try:
            limit = self._get_market_display_limit()
            self._market_view_mode = "all" if limit >= 250 else "quick"
            if limit >= 250:
                self._ensure_market_all_rows()
            self._apply_market_view_mode_button_state()
            self._refresh_market_all_table()
        except Exception:
            pass

    def _set_market_filter(self, filter_key: str, refresh: bool = True) -> None:
        try:
            key = str(filter_key or "volume").strip()
            self._market_sort_key = key
            idx = self.cmb_market_sort.findData(key)
            if idx >= 0 and self.cmb_market_sort.currentIndex() != idx:
                try:
                    self.cmb_market_sort.blockSignals(True)
                    self.cmb_market_sort.setCurrentIndex(idx)
                finally:
                    self.cmb_market_sort.blockSignals(False)
            if refresh:
                self._refresh_market_all_table()
        except Exception:
            pass

    def _on_market_sort_changed(self):
        try:
            self._market_sort_key = self.cmb_market_sort.currentData()
            self._refresh_market_all_table()
        except Exception:
            pass

    def _on_market_sort_toggle(self):
        try:
            if self._market_sort_order == "desc":
                self._market_sort_order = "asc"
                self.btn_market_sort_toggle.setText("↑")
            else:
                self._market_sort_order = "desc"
                self.btn_market_sort_toggle.setText("↓")

            self._refresh_market_all_table()
        except Exception:
            pass

